var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"으음- 종신고용?","JPN":"うーん、終身雇用？","ENG":"Hmm... a lifetime contract?","TWN":"呃呃——終身雇傭？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"…아! 이해했다!","JPN":"……あ！　わかった！","ENG":"...Ah! I get it!","TWN":"……喔！我明白了！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"날 먹으려는 거구나! 내 힘을 빼앗으려고오!","JPN":"私を食べようとしてるんだ！　私の力を奪うためにぃ！","ENG":"You're planning to eat me! To take my power!","TWN":"你是想吃掉我吧！想奪走我的力量！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"안 뺏는다고?","JPN":"奪わない？","ENG":"You're not?","TWN":"不是嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"거짓말! 너 엄청 약한 인간. 더 강해지고 싶으면서.","JPN":"ウソ！　あなた、とても弱い人間。もっと強くなりたいくせに。","ENG":"Liar! You're a really weak human. You clearly want to be stronger.","TWN":"撒謊！你是個非常弱小的人類，明明想變得更強！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"응? 빼앗지 않아도 강해져? 그런 게 돼?","JPN":"うん？　奪わなくても強くなれる？　そんなことができる？","ENG":"Huh? We can get stronger without taking other's power? How does that work?","TWN":"嗯？不搶走我的能力也能變強？有這種事？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"서로를… 도와? 비즈니스으?","JPN":"お互い……助ける？　ビジネスぅー？","ENG":"Help... each other? Business?","TWN":"互相……幫助？是生意嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"정말 그렇게 하면 둘 다 힘을 가질 수 있다고?","JPN":"そしたら本当に2人とも力を得られる？","ENG":"If we really do that, we can both have power?","TWN":"真的簽下去後，兩個人都能獲得力量嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"으음…….","JPN":"うーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"키히힛, 사실 별로 관심 없지롱! 너 없어도 카운터 힘 얼마든지 뺏을 수 있으니까!","JPN":"キヒヒ、実は別に興味ないんだよ！　あなたがいなくても、いくらでもカウンターの力を奪えるから！","ENG":"Keeheehee, I'm actually not interested! I can steal the power of Counters as much as I want, even without you!","TWN":"嘻嘻，其實我根本不在乎！沒有你我也能隨便奪取制裁者的力量！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"그치만 너 안 돕겠다고 하면, 나 계속 방해할 거지? 다 알아.","JPN":"でもあなたを手伝わないって言ったら、ずっと邪魔するつもりなんだよね？　わかってるんだから。","ENG":"But if I don't agree to help you, you're just going to keep getting in my way, right? I know that.","TWN":"但是如果不幫你的話，你會一直妨礙我，對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"엄청 약한 주제에- 똑똑하고 치사해애.","JPN":"弱いくせにー頭いいしズルいー","ENG":"For someone so weak, you're smart and annoying.","TWN":"明明很弱，卻又聰明又狡猾。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"그래도, 너랑 같이 있으면 인간들 나 공격 안 해. 가까이서 봐도 안 도망쳐.","JPN":"でも、あなたと一緒にいると人間たちが攻撃してこない。近くて見ても逃げないんだ。","ENG":"Still, when I'm with you, humans don't attack me. Even up close, they don't run away.","TWN":"不過，和你在一起的話，人類就不會攻擊我。看到我也不會跑走。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"인간들이 믿는 널 따라다니는 거, 나쁘긴 해도- 나쁘지만은 않아.","JPN":"人間たちが信じてるあなたについていくの、悪いけどー悪いだけではない。","ENG":"Following someone humans trust, like you, isn't great. But it's not entirely bad either.","TWN":"人類信任你跟隨你。雖然有點討厭，但也不至於那麼壞。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"그러니까 그거 해볼래. 비즈니스.","JPN":"だからそれやってみる。ビジネス。","ENG":"So I want to try that out. Business.","TWN":"那就，試試看吧。純屬交易。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};